    "smartViews.share_blurb": "लिंक वाला कोई भी व्यक्ति यह स्मार्ट व्यू केवल-पढ़ने योग्य देख सकता है। आप किसी भी समय लिंक रद्द कर सकते हैं।",
    "smartViews.share_copied": "लिंक क्लिपबोर्ड पर कॉपी हुआ",
    "smartViews.share_generated": "शेयर लिंक बना",
    "smartViews.share_link": "शेयर लिंक",
    "smartViews.share_revoke_confirm": "यह लिंक रद्द करें?",
    "smartViews.share_revoked_toast": "शेयर लिंक रद्द हुआ",
    "smartViews.share_rotate": "रोटेट करें",
    "smartViews.share_rotated": "नया शेयर लिंक बना",
    "smartViews.share_url_label": "साझा करने योग्य URL",
